(function () {
  'use strict';

  function initDictionaryFiltersAjax() {
    var page = document.querySelector('.dictionary-archive-page');
    if (!page) return;

    var filters = page.querySelector('.dictionary-filters');
    var results = page.querySelector('[data-dictionary-results]');
    if (!filters || !results) return;

    var inflight = null;

    function isSameOrigin(url) {
      try {
        return new URL(url, window.location.href).origin === window.location.origin;
      } catch (_) {
        return false;
      }
    }

    function setActiveFromURL(urlString) {
      var url;
      try {
        url = new URL(urlString, window.location.href);
      } catch (_) {
        return;
      }
      var selected = (url.searchParams.get('dic_cat') || '').trim();
      var items = filters.querySelectorAll('.learning-column-filters__item');
      items.forEach(function (a) {
        if (a.classList.contains('is-all')) {
          a.classList.toggle('is-active', selected === '');
          return;
        }
        var href = a.getAttribute('href') || '';
        var aURL;
        try {
          aURL = new URL(href, window.location.href);
        } catch (_) {
          a.classList.toggle('is-active', false);
          return;
        }
        var cat = (aURL.searchParams.get('dic_cat') || '').trim();
        a.classList.toggle('is-active', cat !== '' && cat === selected);
      });
    }

    function swapFromHTML(htmlText) {
      var doc = new DOMParser().parseFromString(htmlText, 'text/html');
      var nextResults = doc.querySelector('[data-dictionary-results]');
      var nextFilters = doc.querySelector('.dictionary-filters');
      if (!nextResults) return false;

      results.innerHTML = nextResults.innerHTML;
      if (nextFilters) {
        filters.innerHTML = nextFilters.innerHTML;
      }
      return true;
    }

    function load(url, push) {
      if (push === void 0) push = true;
      if (!isSameOrigin(url)) return;
      if (inflight) inflight.abort();

      var controller = new AbortController();
      inflight = controller;
      page.classList.add('is-loading');

      fetch(url, {
        method: 'GET',
        credentials: 'same-origin',
        headers: { 'X-Requested-With': 'fetch' },
        signal: controller.signal
      })
        .then(function (res) {
          if (!res.ok) throw new Error('fetch failed');
          return res.text();
        })
        .then(function (html) {
          if (!swapFromHTML(html)) return;
          if (push) window.history.pushState({ mythemeDictionary: true }, '', url);
          setActiveFromURL(url);
        })
        .catch(function (e) {
          if (e && e.name === 'AbortError') return;
          window.location.href = url;
        })
        .finally(function () {
          page.classList.remove('is-loading');
          inflight = null;
        });
    }

    page.addEventListener('click', function (e) {
      var a = e.target && e.target.closest ? e.target.closest('a') : null;
      if (!a) return;
      if (a.target === '_blank' || a.hasAttribute('download')) return;
      if (e.metaKey || e.ctrlKey || e.shiftKey || e.altKey) return;
      if (!isSameOrigin(a.href)) return;

      var isFilter = !!a.closest('.dictionary-filters');
      var isPager = !!a.closest('.pagination');
      if (!isFilter && !isPager) return;

      e.preventDefault();
      load(a.href, true);
    });

    window.addEventListener('popstate', function () {
      load(window.location.href, false);
    });

    setActiveFromURL(window.location.href);
  }

  function initDictionaryModal() {
    var ANIM_MS = 140;
    var modal = document.getElementById('dictionary-modal');
    if (!modal) return;

    var body = modal.querySelector('[data-dictionary-modal-body]');
    if (!body) return;

    if (modal.parentNode !== document.body) {
      document.body.appendChild(modal);
    }

    var activeTrigger = null;
    var closeTimer = null;
    var originalBodyPaddingRight = '';
    modal.hidden = true;
    modal.setAttribute('aria-hidden', 'true');
    modal.classList.remove('is-open');
    body.innerHTML = '';
    document.body.classList.remove('dictionary-modal-open');

    function openModal(trigger) {
      var id = trigger.getAttribute('data-dictionary-open');
      if (!id) return;
      var template = document.getElementById(id);
      if (!template) return;

      activeTrigger = trigger;
      var cloned = template.cloneNode(true);
      cloned.removeAttribute('id');
      cloned.hidden = false;
      body.innerHTML = '';
      while (cloned.firstChild) {
        body.appendChild(cloned.firstChild);
      }
      if (closeTimer) {
        clearTimeout(closeTimer);
        closeTimer = null;
      }
      modal.hidden = false;
      modal.setAttribute('aria-hidden', 'false');
      void modal.offsetWidth;
      modal.classList.add('is-open');
      var scrollbarWidth = window.innerWidth - document.documentElement.clientWidth;
      originalBodyPaddingRight = document.body.style.paddingRight || '';
      if (scrollbarWidth > 0) {
        document.body.style.paddingRight = scrollbarWidth + 'px';
      }
      document.body.classList.add('dictionary-modal-open');
    }

    function closeModal() {
      modal.classList.remove('is-open');
      modal.setAttribute('aria-hidden', 'true');
      document.body.classList.remove('dictionary-modal-open');
      document.body.style.paddingRight = originalBodyPaddingRight;
      if (closeTimer) clearTimeout(closeTimer);
      closeTimer = setTimeout(function () {
        modal.hidden = true;
        body.innerHTML = '';
      }, ANIM_MS);
      if (activeTrigger && typeof activeTrigger.focus === 'function') {
        activeTrigger.focus();
      }
      activeTrigger = null;
    }

    document.addEventListener('click', function (e) {
      var openBtn = e.target.closest('[data-dictionary-open]');
      if (openBtn) {
        e.preventDefault();
        openModal(openBtn);
        return;
      }

      var closeBtn = e.target.closest('[data-dictionary-close]');
      if (closeBtn) {
        e.preventDefault();
        closeModal();
      }
    });

    document.addEventListener('keydown', function (e) {
      if (e.key === 'Escape' && !modal.hidden) {
        closeModal();
      }
    });
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', function () {
      initDictionaryFiltersAjax();
      initDictionaryModal();
    });
  } else {
    initDictionaryFiltersAjax();
    initDictionaryModal();
  }
})();
